import{_ as d,Z as e,P as n,g as i,k as s,m as o}from"./chunks/framework.Dp5g00Bf.js";const m=JSON.parse('{"title":"内网静态ip配置","description":"","frontmatter":{},"headers":[],"relativePath":"views/1-开发🌏/3-运维/内网静态ip配置/index.md","filePath":"views/1-开发🌏/3-运维/内网静态ip配置/index.md","lastUpdated":1778336291000}'),l={name:"views/1-开发🌏/3-运维/内网静态ip配置/index.md"};function c(h,t,p,g,_,b){const a=e("NolebaseGitContributors"),r=e("NolebaseGitChangelog");return n(),i("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1778336291000"},[t[0]||(t[0]=s('<h1 id="内网静态ip配置" tabindex="-1">内网静态ip配置 <a class="header-anchor" href="#内网静态ip配置" aria-label="Permalink to &quot;内网静态ip配置&quot;">​</a></h1><p>很多时候，我们希望内网的ip能够固定。如果不固定的话，路由器 或者服务器重启很可能会分配到新的ip地址导致老的服务无法访问。</p><h2 id="配置参数" tabindex="-1">配置参数 <a class="header-anchor" href="#配置参数" aria-label="Permalink to &quot;配置参数&quot;">​</a></h2><h5 id="_1、ip地址" tabindex="-1">1、ip地址 <a class="header-anchor" href="#_1、ip地址" aria-label="Permalink to &quot;1、ip地址&quot;">​</a></h5><p>相当于门牌号，注意该ip地址必须是没有被分配的地址。</p><h5 id="_2、dns服务" tabindex="-1">2、dns服务 <a class="header-anchor" href="#_2、dns服务" aria-label="Permalink to &quot;2、dns服务&quot;">​</a></h5><p>dns相当于一本电话簿，主要的作用适用于解析域名。</p><h5 id="_3、子网掩码-前缀长度" tabindex="-1">3、子网掩码(前缀长度) <a class="header-anchor" href="#_3、子网掩码-前缀长度" aria-label="Permalink to &quot;3、子网掩码(前缀长度)&quot;">​</a></h5><p>相当于小区的划分规则，它会告诉你哪部分是小区名，哪部分是几幢几号房间。所以它的作用就是告诉电脑如何拆分ip地址。</p><p>假设你的IP地址是 <code>192.168.1.100</code>，子网掩码是 <code>255.255.255.0</code>（相当于规则： <strong>前三段是小区名</strong> ）：</p><ul><li><strong>网络部分</strong> （小区名）= <code>192.168.1</code>→ 整个小区叫“192.168.1小区”</li><li><strong>主机部分</strong> （楼栋房间号）= <code>.100</code>→ 你是小区里的100号住户</li></ul><p>✅ <strong>同一小区的住户</strong> （比如 <code>192.168.1.101</code>）可以直接敲门聊天（直接通信）。</p><p>❌ <strong>其他小区的</strong> （比如 <code>192.168.2.50</code>）必须通过邮局（路由器）中转才能联系。</p><h3 id="❓-为什么需要子网掩码" tabindex="-1">❓ <strong>为什么需要子网掩码？</strong> <a class="header-anchor" href="#❓-为什么需要子网掩码" aria-label="Permalink to &quot;❓ **为什么需要子网掩码？**&quot;">​</a></h3><ol><li><strong>防止混乱</strong> ：没有它，电脑不知道谁和自己是一伙的（同一小区）。</li><li><strong>节省资源</strong> ：把大网络拆成小小区（子网），方便管理（比如一栋楼装一个路由器）。</li><li><strong>加速通信</strong> ：同一小区的设备直接对话，不用绕远路找路由器。</li></ol><hr><h3 id="🛠️-常见子网掩码对照表" tabindex="-1">🛠️ <strong>常见子网掩码对照表</strong> <a class="header-anchor" href="#🛠️-常见子网掩码对照表" aria-label="Permalink to &quot;🛠️ **常见子网掩码对照表**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子网掩码写法</th><th>通俗含义</th><th>适用场景</th></tr></thead><tbody><tr><td><code>255.255.255.0</code></td><td>前三段是小区名（/24）</td><td>普通家庭/小型公司网络</td></tr><tr><td><code>255.255.0.0</code></td><td>前两段是小区名（/16）</td><td>中型校园网</td></tr><tr><td><code>255.0.0.0</code></td><td>第一段是小区名（/8）</td><td>超大型运营商网络</td></tr></tbody></table><blockquote><p>✨ <strong>小贴士</strong> ：现在很多直接用 <code>/24</code>代替 <code>255.255.255.0</code>，意思一样！</p></blockquote><h5 id="_4、网关-路由器" tabindex="-1">4、网关(路由器) <a class="header-anchor" href="#_4、网关-路由器" aria-label="Permalink to &quot;4、网关(路由器)&quot;">​</a></h5><p>同一局域网如果两个内网ip不在同一个子网，那么互相通信需要经过网关。网关的地址有时候和dns地址是同一个。 在计算机网络中， <strong>网关（Gateway）</strong> 是一种关键的网络设备或逻辑组件，主要用于连接 <strong>不同类型的网络</strong> （或同一网络的不同网段），并解决它们之间的 <strong>协议差异</strong> ，实现跨网络通信。通俗来说，网关是网络的“翻译官”和“桥梁”，负责将一种网络格式的数据转换为另一种网络能理解的格式，确保不同网络间的信息互通。</p>',21)),o(a),o(r)])}const f=d(l,[["render",c]]);export{m as __pageData,f as default};
